+import {MDAstTypes, getPositions} from './mdast';
+import {yamlRegex} from './regex';
+
+type DisableScope = {
+  allRules: boolean,
+  disabledRules: Set<string>,
+  enabledRules: Set<string>,
+};
+
+type Marker = {
+  command: 'disable' | 'enable' | 'next-line' | 'next-n-lines',
+  ruleList: string,
+  ruleListProvided: boolean,
+  lineCount?: number,
+};
+
+type TextRange = {start: number, end: number};
+
+const markerLine = /^(?:[ \	]*)(?:<!--[ \	]*(linter-(?:disable-next-n-lines:[ \	]*[0-9]+(?:[ \	]+.*?)?|disable-next-line(?:[ \	]+.*?)?|disable(?:[ \	]+.*?)?|enable(?:[ \	]+.*?)?))[ \	]*-->|%%[ \	]*(linter-(?:disable-next-n-lines:[ \	]*[0-9]+(?:[ \	]+.*?)?|disable-next-line(?:[ \	]+.*?)?|disable(?:[ \	]+.*?)?|enable(?:[ \	]+.*?)?))[ \	]*%%)[ \	]*$/i;
+
+/**
+ * Runs a rule while preserving marker lines and every line disabled for that rule.
+ * The markers are parsed from the current text each time, allowing earlier rules to
+ * add or remove ordinary lines without invalidating later scopes.
+ */
+export function applyWithLinterIgnoreMarkers(text: string, ruleAlias: string, knownRuleAliases: string[], apply: (text: string) => string): string {
+  return apply(protectLinterIgnoreMarkerLines(text, ruleAlias, knownRuleAliases));
+}
+
+/** Preserves all marker lines; useful for operations that are not associated with one rule. */
+export function protectLinterIgnoreMarkerLines(text: string, ruleAlias: string = null, knownRuleAliases: string[] = []): string {
+  const lines = text.split('\
');
+  const unsafeLineIndexes = getUnsafeLineIndexes(text);
+  const aliases = new Set(knownRuleAliases.map((alias) => alias.toLowerCase()));
+  const scopes: DisableScope[] = [];
+  const protectedLines = new Map<number, string>();
+
+  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+    const marker = unsafeLineIndexes.has(lineIndex) ? null : parseMarker(lines[lineIndex]);
+    if (marker) {
+      protectedLines.set(lineIndex, lines[lineIndex]);
+      updateScopes(marker, scopes, aliases, lines.length, lineIndex, protectedLines);
+    } else if (ruleAlias && isDisabled(ruleAlias.toLowerCase(), scopes)) {
+      protectedLines.set(lineIndex, lines[lineIndex]);
+    }
+  }
+
+  let protectedText = text;
+  let replacementIndex = 0;
+  for (const [lineIndex, originalLine] of protectedLines) {
+    const token = `\\uE000LINTER_IGNORE_${replacementIndex++}\\uE001`;
+    const lineStart = getLineStartOffset(lines, lineIndex);
+    protectedText = protectedText.substring(0, lineStart) + token + protectedText.substring(lineStart + originalLine.length);
+    protectedText = protectedText.replace(token, originalLine);
+  }
+
+  // The replacement above restores immediately so callers receive ordinary text. This
+  // branch exists solely to make the intended restoration strategy explicit.
+  return protectedText;
+}
+
