+  }
+  const marker = content.trim();
+  const nextNLines = /^linter-disable-next-n-lines:[ \	]*([0-9]+)(?:[ \	]+(.*))?$/i.exec(marker);
+  if (nextNLines) {
+    const lineCount = Number(nextNLines[1]);
+    if (!Number.isSafeInteger(lineCount) || lineCount <= 0) {
+      return null;
+    }
+    return {command: 'next-n-lines', ruleList: nextNLines[2] ?? '', ruleListProvided: nextNLines[2] !== undefined, lineCount};
+  }
+  const nextLine = /^linter-disable-next-line(?:[ \	]+(.*))?$/i.exec(marker);
+  if (nextLine) {
+    return {command: 'next-line', ruleList: nextLine[1] ?? '', ruleListProvided: nextLine[1] !== undefined};
+  }
+  const disable = /^linter-disable(?:[ \	]+(.*))?$/i.exec(marker);
+  if (disable) {
+    return {command: 'disable', ruleList: disable[1] ?? '', ruleListProvided: disable[1] !== undefined};
+  }
+  const enable = /^linter-enable(?:[ \	]+(.*))?$/i.exec(marker);
+  return enable ? {command: 'enable', ruleList: enable[1] ?? '', ruleListProvided: enable[1] !== undefined} : null;
+}
+
+function getUnsafeLineIndexes(text: string): Set<number> {
+  const ranges: TextRange[] = [];
+  const yaml = text.match(yamlRegex);
+  if (yaml?.index === 0) {
+    ranges.push({start: 0, end: yaml[0].length});
+  }
+  for (const type of [MDAstTypes.Code, MDAstTypes.InlineCode, MDAstTypes.Math, MDAstTypes.InlineMath]) {
+    for (const position of getPositions(type, text)) {
+      ranges.push({start: position.start.offset, end: position.end.offset});
+    }
+  }
+  const unsafe = new Set<number>();
+  let offset = 0;
+  for (const [index, line] of text.split('\
').entries()) {
+    if (ranges.some((range) => offset >= range.start && offset < range.end)) {
+      unsafe.add(index);
+    }
+    offset += line.length + 1;
+  }
+  return unsafe;
+}
+
+function getLineStartOffset(lines: string[], lineIndex: number): number {
+  let offset = 0;
+  for (let index = 0; index < lineIndex; index++) {
+    offset += lines[index].length + 1;
+  }
+  return offset;
